class Solution {
    public int findNumberOfLIS(int[] nums) {
        int n = nums.length;
        int[] dp = new int[n];
        int[] count = new int[n];
        int maxLength = 1;
        int total = 1;

        for (int i = 0; i < n; i++) {
            dp[i] = 1;
            count[i] = 1;
        }

        for (int i = 1; i < n; i++) {
            for (int j = 0; j < i; j++) {
                if (nums[i] > nums[j]) {
                    if (dp[i] < dp[j] + 1) {
                        dp[i] = dp[j] + 1;
                        count[i] = count[j];
                    } else if (dp[i] == dp[j] + 1) {
                        count[i] += count[j];
                    }
                }
            }
            if (dp[i] > maxLength) {
                maxLength = dp[i];
                total = count[i];
            } else if (dp[i] == maxLength) {
                total += count[i];
            }
        }

        return total;
    }
}
